import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  username: string;
  displayName: string;
  robux: number;
  avatarUrl?: string; // We'll use the 3D scene instead, but good to have
}

export interface Game {
  id: string;
  title: string;
  creator: string;
  thumbnail: string;
  likes: string;
  playing: number;
}

export enum Page {
  HOME = 'HOME',
  PROFILE = 'PROFILE',
  GAMES = 'GAMES',
  AVATAR = 'AVATAR'
}

import React, { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, ContactShadows, Environment } from '@react-three/drei';
import * as THREE from 'three';

// Procedural "Noob" Style Roblox Character
const RobloxCharacter = () => {
  const group = useRef<THREE.Group>(null);

  useFrame((state) => {
    if (group.current) {
      // Idle Animation: Floating and slight rotation
      const t = state.clock.getElapsedTime();
      group.current.position.y = Math.sin(t * 2) * 0.05 - 0.5; 
      group.current.rotation.y = Math.sin(t * 0.5) * 0.1;

      // Arm swing breathing
      const leftArm = group.current.getObjectByName("LeftArm");
      const rightArm = group.current.getObjectByName("RightArm");

      if (leftArm) leftArm.rotation.x = Math.sin(t * 2) * 0.05;
      if (rightArm) rightArm.rotation.x = -Math.sin(t * 2) * 0.05;
    }
  });

  // Material settings for plastic toy look
  const materialProps = { roughness: 0.3, metalness: 0.1 };

  return (
    <group ref={group} dispose={null}>
      {/* Head - Yellow */}
      <mesh position={[0, 1.6, 0]} name="Head">
        <cylinderGeometry args={[0.35, 0.35, 0.7, 32]} />
        <meshStandardMaterial color="#F5CD30" {...materialProps} />
        {/* Face Decal (Simulated with simple geometry for eyes/mouth) */}
        <mesh position={[0.12, 0.05, 0.3]} rotation={[0, 0, 0]}>
             <sphereGeometry args={[0.04]} />
             <meshBasicMaterial color="black" />
        </mesh>
        <mesh position={[-0.12, 0.05, 0.3]}>
             <sphereGeometry args={[0.04]} />
             <meshBasicMaterial color="black" />
        </mesh>
        <mesh position={[0, -0.15, 0.3]} scale={[1, 0.5, 1]}>
             <torusGeometry args={[0.06, 0.02, 16, 100, Math.PI]} rotation={[0,0,Math.PI]} />
             <meshBasicMaterial color="black" />
        </mesh>
      </mesh>

      {/* Torso - Blue */}
      <mesh position={[0, 0.8, 0]} name="Torso">
        <boxGeometry args={[1, 1, 0.5]} />
        <meshStandardMaterial color="#0047AB" {...materialProps} />
        {/* Logo/Graphic on shirt */}
        <mesh position={[0, 0.1, 0.26]}>
           <planeGeometry args={[0.3, 0.3]} />
           <meshBasicMaterial color="#ffffff" transparent opacity={0.8} />
        </mesh>
      </mesh>

      {/* Left Arm - Yellow */}
      <mesh position={[-0.75, 0.8, 0]} name="LeftArm">
        <boxGeometry args={[0.5, 1, 0.5]} />
        <meshStandardMaterial color="#F5CD30" {...materialProps} />
      </mesh>

      {/* Right Arm - Yellow */}
      <mesh position={[0.75, 0.8, 0]} name="RightArm">
        <boxGeometry args={[0.5, 1, 0.5]} />
        <meshStandardMaterial color="#F5CD30" {...materialProps} />
      </mesh>

      {/* Left Leg - Green */}
      <mesh position={[-0.26, -0.2, 0]} name="LeftLeg">
        <boxGeometry args={[0.48, 1, 0.5]} />
        <meshStandardMaterial color="#A2C429" {...materialProps} />
      </mesh>

      {/* Right Leg - Green */}
      <mesh position={[0.26, -0.2, 0]} name="RightLeg">
        <boxGeometry args={[0.48, 1, 0.5]} />
        <meshStandardMaterial color="#A2C429" {...materialProps} />
      </mesh>
    </group>
  );
};

export const AvatarScene: React.FC = () => {
  return (
    <div className="w-full h-full min-h-[300px] relative bg-gradient-to-b from-gray-800 to-gray-900 rounded-lg overflow-hidden border border-gray-700">
      <div className="absolute top-2 left-2 z-10 bg-black/50 px-2 py-1 rounded text-xs font-bold text-white uppercase tracking-wider">
        Vista 3D
      </div>
      <Canvas shadows dpr={[1, 2]}>
        <PerspectiveCamera makeDefault position={[0, 1, 4]} fov={50} />

        <ambientLight intensity={0.7} />
        <spotLight position={[10, 10, 10]} angle={0.15} penumbra={1} intensity={1} castShadow />
        <pointLight position={[-10, -10, -10]} intensity={0.5} />

        <group position={[0, -0.5, 0]}>
            <RobloxCharacter />
            <ContactShadows resolution={1024} scale={10} blur={2} opacity={0.5} far={10} color="#000000" />
        </group>

        <OrbitControls enablePan={false} minPolarAngle={Math.PI / 4} maxPolarAngle={Math.PI / 1.5} />
        <Environment preset="city" />
      </Canvas>
    </div>
  );
};

