import React, { useState, useEffect } from 'react';
import { HashRouter } from 'react-router-dom';
import { LoginPage } from './pages/Login';
import { HomePage } from './pages/Home';
import { Navbar } from './components/Navbar';
import { Sidebar } from './components/Sidebar';
import { User, Page } from './types';
import { AvatarScene } from './components/AvatarScene';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [sidebarOpen, setSidebarOpen] = useState<boolean>(true);
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [user, setUser] = useState<User | null>(null);

  // Initial redirect check or session restore could go here
  useEffect(() => {
    // Check if user session exists (mock)
    const storedUser = localStorage.getItem('robloxCloneUser');
    if (storedUser) {
        setUser(JSON.parse(storedUser));
        setIsAuthenticated(true);
    }
  }, []);

  const handleLogin = (username: string) => {
    const newUser = {
      username: username,
      displayName: username,
      robux: 1540
    };
    setUser(newUser);
    localStorage.setItem('robloxCloneUser', JSON.stringify(newUser));
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('robloxCloneUser');
    setIsAuthenticated(false);
    setCurrentPage(Page.HOME);
  };

  // If not authenticated, show Login Page (exactly like Roblox landing)
  if (!isAuthenticated) {
    return <LoginPage onLogin={handleLogin} />;
  }

  // Authenticated Layout
  return (
    <HashRouter>
      <div className="min-h-screen bg-[#232527] flex flex-col">
        {user && (
            <Navbar 
                user={user} 
                onToggleSidebar={() => setSidebarOpen(!sidebarOpen)}
                onLogout={handleLogout}
            />
        )}

        <div className="flex flex-1 pt-[0px] relative">
          <Sidebar 
            isOpen={sidebarOpen} 
            currentPage={currentPage} 
            onNavigate={setCurrentPage}
            userName={user?.displayName || 'Guest'}
          />

          <main 
            className={`flex-1 transition-all duration-300 ${sidebarOpen ? 'md:ml-64' : 'md:ml-16'} ml-0`}
          >
            {currentPage === Page.HOME && user && <HomePage username={user.displayName} />}

            {currentPage === Page.PROFILE && (
                <div className="flex flex-col items-center justify-center h-full min-h-[500px] text-gray-400">
                    <h2 className="text-2xl font-bold text-white mb-4">Perfil de Usuario</h2>
                    <p>Esta sección está en construcción.</p>
                </div>
            )}

            {currentPage === Page.AVATAR && (
                <div className="p-8 max-w-4xl mx-auto h-[80vh]">
                     <h2 className="text-3xl font-bold text-white mb-6">Editor de Avatar</h2>
                     <div className="bg-[#1a1c1e] rounded-xl border border-[#393b3d] h-full overflow-hidden flex flex-col md:flex-row">
                        <div className="flex-1 h-full relative p-4">
                             <AvatarScene />
                        </div>
                        <div className="w-full md:w-80 bg-[#232527] p-4 border-l border-[#393b3d]">
                            <h3 className="text-white font-bold mb-4">Personalización</h3>
                            <div className="space-y-4">
                                <div className="p-3 bg-white/5 rounded cursor-pointer hover:bg-white/10">
                                    <span className="text-sm font-medium text-gray-300">Cuerpo</span>
                                </div>
                                <div className="p-3 bg-white/5 rounded cursor-pointer hover:bg-white/10">
                                    <span className="text-sm font-medium text-gray-300">Ropa</span>
                                </div>
                                <div className="p-3 bg-white/5 rounded cursor-pointer hover:bg-white/10">
                                    <span className="text-sm font-medium text-gray-300">Animaciones</span>
                                </div>
                            </div>
                        </div>
                     </div>
                </div>
            )}

            {currentPage === Page.GAMES && (
                 <div className="p-8">
                     <h2 className="text-2xl font-bold text-white mb-4">Todas las Experiencias</h2>
                     {/* Reuse home content or list more games */}
                     <p className="text-gray-400">Explora millones de experiencias...</p>
                 </div>
            )}
          </main>
        </div>
      </div>
    </HashRouter>
  );
}

export default App;

