  id: string;
  name: string;
  type: 'face' | 'hat' | 'shirt';
  price: number; // 0 for free
  thumbnail: string; // URL or placeholder
  assetUrl: string; // The actual content
  creator: string;
}

export enum Page {
  HOME = 'HOME',
  PROFILE = 'PROFILE',
  GAMES = 'GAMES',
  AVATAR = 'AVATAR',
  STORE = 'STORE'
}

import React, { useRef, useState, useEffect } from 'react';
import { Canvas, useFrame, useLoader } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, ContactShadows, Environment, useGLTF } from '@react-three/drei';
import * as THREE from 'three';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader';
import { AvatarConfig } from '../types';

// Helper component to load external GLTF/GLB models
const AccessoryModel = ({ url, position, scale }: { url: string; position: any; scale: any }) => {
  const { scene } = useGLTF(url);
  // Clone to avoid mutation issues if used multiple times
  const clone = React.useMemo(() => scene.clone(), [scene]);
  return <primitive object={clone} position={position} scale={scale} />;
};

// Helper for dynamic textures
const FaceTexture = ({ url }: { url: string | null }) => {
  const texture = useLoader(THREE.TextureLoader, url || 'https://via.placeholder.com/1x1/transparent'); // Fallback to avoid crash

  if (!url) return null;

  return (
    <mesh position={[0, 0, 0.36]} rotation={[0, 0, 0]}>
      <planeGeometry args={[0.25, 0.25]} />
      <meshBasicMaterial map={texture} transparent opacity={1} />
    </mesh>
  );
};

const RobloxCharacter = ({ config }: { config: AvatarConfig }) => {
  const group = useRef<THREE.Group>(null);

  useFrame((state) => {
    if (group.current) {
      const t = state.clock.getElapsedTime();
      // Breathing animation
      group.current.position.y = Math.sin(t * 1) * 0.02 - 0.5;

      const leftArm = group.current.getObjectByName("LeftArm");
      const rightArm = group.current.getObjectByName("RightArm");

      if (leftArm) leftArm.rotation.x = Math.sin(t * 1.5) * 0.1;
      if (rightArm) rightArm.rotation.x = -Math.sin(t * 1.5) * 0.1;
    }
  });

  const materialProps = { roughness: 0.3, metalness: 0.1 };

  return (
    <group ref={group} dispose={null}>
      {/* Head */}
      <group position={[0, 1.6, 0]} name="HeadGroup">
        <mesh name="Head">
           {/* Slightly rounded head like modern Roblox avatars or Classic Cylinder */}
          <cylinderGeometry args={[0.35, 0.35, 0.7, 32]} />
          <meshStandardMaterial color={config.bodyColors.head} {...materialProps} />
        </mesh>

        {/* Dynamic Face Texture */}
        {config.faceTextureUrl && !config.hideFace && (
            <React.Suspense fallback={null}>
               <FaceTexture url={config.faceTextureUrl} />
            </React.Suspense>
        )}

        {/* Default Face if no texture and not hidden */}
        {!config.faceTextureUrl && !config.hideFace && (
          <group>
             <mesh position={[0.12, 0.05, 0.3]} rotation={[0, 0, 0]}>
                 <sphereGeometry args={[0.04]} />
                 <meshBasicMaterial color="black" />
            </mesh>
            <mesh position={[-0.12, 0.05, 0.3]}>
                 <sphereGeometry args={[0.04]} />
                 <meshBasicMaterial color="black" />
            </mesh>
            <mesh position={[0, -0.15, 0.3]} scale={[1, 0.5, 1]}>
                 <torusGeometry args={[0.06, 0.02, 16, 100, Math.PI]} rotation={[0,0,Math.PI]} />
                 <meshBasicMaterial color="black" />
            </mesh>
          </group>
        )}

        {/* Imported 3D Hat/Accessory */}
        {config.accessories.hatModelUrl && (
          <React.Suspense fallback={null}>
            <AccessoryModel 
              url={config.accessories.hatModelUrl} 
              position={[0, 0.4, 0]} 
              scale={[0.8, 0.8, 0.8]} 
            />
          </React.Suspense>
        )}
      </group>

      {/* Torso */}
