import React, { useState, useRef, Suspense } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, TransformControls, Grid, Environment, Sky } from '@react-three/drei';
import { MousePointer2, Move, Maximize, RotateCw, Box, Circle, Triangle, Cylinder, Save, Play } from 'lucide-react';
import * as THREE from 'three';
import { MapObject } from '../types';

// Initial scene setup
const INITIAL_MAP: MapObject[] = [
  { 
    id: 'baseplate', 
    name: 'Baseplate', 
    type: 'Part', 
    position: [0, -0.5, 0], 
    rotation: [0, 0, 0], 
    scale: [50, 1, 50], 
    color: '#2b2b2b', 
    material: 'Plastic', 
    transparency: 0,
    anchored: true 
  },
  { 
    id: 'spawn', 
    name: 'SpawnLocation', 
    type: 'Part', 
    position: [0, 0.5, 0], 
    rotation: [0, 0, 0], 
    scale: [4, 1, 4], 
    color: '#a3a2a5', 
    material: 'Plastic', 
    transparency: 0,
    anchored: true 
  }
];

// Helper to get geometry based on type
const PartGeometry = ({ type }: { type: MapObject['type'] }) => {
  switch (type) {
    case 'Sphere': return <sphereGeometry args={[0.5, 32, 32]} />;
    case 'Cylinder': return <cylinderGeometry args={[0.5, 0.5, 1, 32]} />;
    case 'Wedge': return <coneGeometry args={[0.5, 1, 4]} />; // Simplified wedge
    case 'Part': default: return <boxGeometry args={[1, 1, 1]} />;
  }
};

// Main Scene Component
const StudioScene = ({ 
  objects, 
  selectedId, 
  onSelect, 
  onTransform, 
  mode 
}: { 
  objects: MapObject[], 
  selectedId: string | null, 
  onSelect: (id: string | null) => void,
  onTransform: (id: string, newProps: Partial<MapObject>) => void,
  mode: 'translate' | 'rotate' | 'scale'
}) => {

  return (
    <>
      <ambientLight intensity={0.5} />
      <directionalLight position={[10, 10, 5]} intensity={1} castShadow />
      <Sky sunPosition={[100, 20, 100]} />
      <Grid infiniteGrid sectionSize={4} sectionColor="#6f6f6f" cellColor="#4a4a4a" position={[0, -0.01, 0]} />

      {objects.map((obj) => (
        <React.Fragment key={obj.id}>
          {selectedId === obj.id ? (
            <TransformControls 
              mode={mode} 
              onObjectChange={(e: any) => {
                 if(e?.target?.object) {
                    const o = e.target.object;
                    onTransform(obj.id, {
                        position: [o.position.x, o.position.y, o.position.z],
                        rotation: [o.rotation.x, o.rotation.y, o.rotation.z],
                        scale: [o.scale.x, o.scale.y, o.scale.z]
                    });
                 }
              }}
            >
               <mesh 
                position={new THREE.Vector3(...obj.position)} 
                rotation={new THREE.Euler(...obj.rotation)} 
                scale={new THREE.Vector3(...obj.scale)}
                onClick={(e) => {
                  e.stopPropagation();
                  onSelect(obj.id);
                }}
              >
                <PartGeometry type={obj.type} />
                <meshStandardMaterial 
                   color={obj.color} 
                   transparent={obj.transparency > 0} 
                   opacity={1 - obj.transparency}
                   roughness={obj.material === 'Neon' ? 0 : 0.5}
                   emissive={obj.material === 'Neon' ? obj.color : 'black'}
                   emissiveIntensity={obj.material === 'Neon' ? 1 : 0}
                />
              </mesh>
            </TransformControls>
          ) : (
            <mesh 
              position={new THREE.Vector3(...obj.position)} 
              rotation={new THREE.Euler(...obj.rotation)} 
              scale={new THREE.Vector3(...obj.scale)}
              onClick={(e) => {
                e.stopPropagation();
                onSelect(obj.id);
              }}
            >
              <PartGeometry type={obj.type} />
              <meshStandardMaterial 
                 color={obj.color} 
                 transparent={obj.transparency > 0} 
                 opacity={1 - obj.transparency}
                 roughness={obj.material === 'Neon' ? 0 : 0.5}
                 emissive={obj.material === 'Neon' ? obj.color : 'black'}
                 emissiveIntensity={obj.material === 'Neon' ? 1 : 0}
              />
            </mesh>
          )}
        </React.Fragment>
      ))}

      {/* Click background to deselect */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -1, 0]} onClick={() => onSelect(null)}>
         <planeGeometry args={[1000, 1000]} />
         <meshBasicMaterial visible={false} />
      </mesh>
    </>
  );
};

