// --- HELPERS ---

const PartGeometry = ({ type }: { type: MapObject['type'] }) => {
  switch (type) {
    case 'Sphere': return <sphereGeometry args={[0.5, 32, 32]} />;
    case 'Cylinder': return <cylinderGeometry args={[0.5, 0.5, 1, 32]} />;
    case 'Wedge': return <coneGeometry args={[0.5, 1, 4]} />;
    case 'Part': default: return <boxGeometry args={[1, 1, 1]} />;
  }
};

const getMaterial = (type: string, color: string) => {
    // Basic material simulation
    return <meshStandardMaterial 
        color={color}
        roughness={type === 'Plastic' ? 0.5 : type === 'Neon' ? 0 : 0.9}
        metalness={type === 'Plastic' ? 0 : 0.1}
        emissive={type === 'Neon' ? color : 'black'}
        emissiveIntensity={type === 'Neon' ? 1 : 0}
        map={type === 'Brick' ? null : null} // In a real app, load textures
    />;
}

// --- PLAYER CONTROLLER FOR TEST MODE ---

const PlayerController = ({ avatarConfig, mapObjects }: { avatarConfig: AvatarConfig, mapObjects: MapObject[] }) => {
    const [pos, setPos] = useState(new THREE.Vector3(0, 2, 0));
    const [rot, setRot] = useState(new THREE.Euler(0, 0, 0));
    const [isMoving, setIsMoving] = useState(false);
    const [isJumping, setIsJumping] = useState(false);

    // Simple Physics State
    const velocity = useRef(new THREE.Vector3(0, 0, 0));
    const canJump = useRef(true);
    const keys = useRef<{ [key: string]: boolean }>({});

    useEffect(() => {
        const onKeyDown = (e: KeyboardEvent) => keys.current[e.code] = true;
        const onKeyUp = (e: KeyboardEvent) => keys.current[e.code] = false;
        window.addEventListener('keydown', onKeyDown);
        window.addEventListener('keyup', onKeyUp);
        return () => {
            window.removeEventListener('keydown', onKeyDown);
            window.removeEventListener('keyup', onKeyUp);
        };
    }, []);

    useFrame((state) => {
        const speed = 0.15;
        const jumpForce = 0.3;
        const gravity = 0.015;

        // Horizontal Movement
        const forward = new THREE.Vector3(0, 0, -1).applyAxisAngle(new THREE.Vector3(0, 1, 0), rot.y);
        const right = new THREE.Vector3(1, 0, 0).applyAxisAngle(new THREE.Vector3(0, 1, 0), rot.y);

        let moveVec = new THREE.Vector3(0, 0, 0);
        let moving = false;

        if (keys.current['KeyW']) { moveVec.add(forward); moving = true; }
        if (keys.current['KeyS']) { moveVec.sub(forward); moving = true; }
        if (keys.current['KeyA']) { moveVec.sub(right); moving = true; }
        if (keys.current['KeyD']) { moveVec.add(right); moving = true; }

        if (moving) moveVec.normalize().multiplyScalar(speed);

        // Rotation (Rotate character to face movement direction if needed, but for now we follow camera or static controls)
        // Simple 3rd person rotation: Rotate pos based on keys?
        // Let's rotate the character based on the pressed key relative to camera later.
        // For now, A/D rotates character, W/S moves forward/back relative to character

        const rotationSpeed = 0.05;
        if (keys.current['ArrowLeft'] || keys.current['KeyA']) {
            setRot(r => new THREE.Euler(r.x, r.y + rotationSpeed, r.z));
            // moveVec is calculated based on world, let's fix movement relative to character facing
            moveVec = new THREE.Vector3(0,0,0); // Override strafing
            if (keys.current['KeyW']) moveVec.add(forward.multiplyScalar(speed)); // Recalc forward
            if (keys.current['KeyS']) moveVec.sub(forward.multiplyScalar(speed));
        }
        if (keys.current['ArrowRight'] || keys.current['KeyD']) {
             setRot(r => new THREE.Euler(r.x, r.y - rotationSpeed, r.z));
             moveVec = new THREE.Vector3(0,0,0);
             if (keys.current['KeyW']) moveVec.add(forward.multiplyScalar(speed));
             if (keys.current['KeyS']) moveVec.sub(forward.multiplyScalar(speed));
        }

        // Apply Movement
        velocity.current.x = moveVec.x;
        velocity.current.z = moveVec.z;

        // Jump
        if (keys.current['Space'] && canJump.current) {
            velocity.current.y = jumpForce;
            canJump.current = false;
            setIsJumping(true);
        }

        // Gravity
        velocity.current.y -= gravity;

        // Floor Collision (Simple Plane at y=0 or check MapObjects)
        // Hardcoded ground check at Y=0 (Baseplate level approx)
        let nextY = pos.y + velocity.current.y;
        if (nextY <= 0) {
            nextY = 0;
            velocity.current.y = 0;
            canJump.current = true;
            setIsJumping(false);
        } else {
            // Check collisions with map objects (Simplified: Box bounding)
            // Ideally we use a physics engine, but here we just check if feet enter a box
        }

        const nextPos = pos.clone().add(velocity.current);
        // Floor constraint
        if(nextPos.y < 0) nextPos.y = 0;

        setPos(nextPos);
        setIsMoving(moving || Math.abs(velocity.current.x) > 0.01 || Math.abs(velocity.current.z) > 0.01);

        // Camera Follow
        state.camera.position.x = THREE.MathUtils.lerp(state.camera.position.x, nextPos.x - Math.sin(rot.y) * 8, 0.1);
        state.camera.position.z = THREE.MathUtils.lerp(state.camera.position.z, nextPos.z - Math.cos(rot.y) * 8, 0.1);
        state.camera.position.y = THREE.MathUtils.lerp(state.camera.position.y, nextPos.y + 4, 0.1);
        state.camera.lookAt(nextPos.x, nextPos.y + 2, nextPos.z);
    });

    return (
        <RobloxCharacter 
            config={avatarConfig} 
            position={[pos.x, pos.y, pos.z]} 
            rotation={[rot.x, rot.y, rot.z]} 
            isMoving={isMoving}
            isJumping={isJumping}
        />
    );
};

