}

const INITIAL_MAP: MapObject[] = [
    { id: 'baseplate', name: 'Baseplate', type: 'Part', position: [0, -0.5, 0], rotation: [0, 0, 0], scale: [100, 1, 100], color: '#2b2b2b', material: 'Plastic', transparency: 0, anchored: true, canCollide: true },
    { id: 'spawn', name: 'SpawnLocation', type: 'Part', position: [0, 0.1, 0], rotation: [0, 0, 0], scale: [6, 0.2, 6], color: '#a3a2a5', material: 'Plastic', transparency: 0, anchored: true, canCollide: true }
];

export const StudioPage: React.FC<StudioProps> = ({ onPublish, avatarConfig }) => {
  const [objects, setObjects] = useState<MapObject[]>(INITIAL_MAP);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [transformMode, setTransformMode] = useState<'translate' | 'rotate' | 'scale'>('translate');
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [gameTitle, setGameTitle] = useState("Mi Juego de Roblox");

  // --- ACTIONS ---

  const handleAddObject = (type: MapObject['type']) => {
    const newObj: MapObject = {
      id: Date.now().toString(),
      name: type,
      type: type,
      position: [0, 5, 0],
      rotation: [0, 0, 0],
      scale: [1, 1, 1],
      color: '#A2A2A2',
      material: 'Plastic',
      transparency: 0,
      anchored: false,
      canCollide: true
    };
    setObjects([...objects, newObj]);
    setSelectedId(newObj.id);
  };

  const handleAddHouse = () => {
      // Procedurally generate a simple Brookhaven-style house (Walls + Roof)
      const baseId = Date.now();
      const x = (Math.random() - 0.5) * 40;
      const z = (Math.random() - 0.5) * 40;
      const houseParts: MapObject[] = [
          // Floor
          { id: `${baseId}_floor`, name: 'HouseFloor', type: 'Part', position: [x, 0.1, z], rotation: [0,0,0], scale: [15, 0.2, 15], color: '#5e4033', material: 'Wood', transparency: 0, anchored: true, canCollide: true },
          // Walls
          { id: `${baseId}_w1`, name: 'Wall', type: 'Part', position: [x-7, 3, z], rotation: [0,0,0], scale: [1, 6, 15], color: '#e8e1d5', material: 'Plastic', transparency: 0, anchored: true, canCollide: true },
          { id: `${baseId}_w2`, name: 'Wall', type: 'Part', position: [x+7, 3, z], rotation: [0,0,0], scale: [1, 6, 15], color: '#e8e1d5', material: 'Plastic', transparency: 0, anchored: true, canCollide: true },
          { id: `${baseId}_w3`, name: 'Wall', type: 'Part', position: [x, 3, z-7], rotation: [0,0,0], scale: [15, 6, 1], color: '#e8e1d5', material: 'Plastic', transparency: 0, anchored: true, canCollide: true },
          { id: `${baseId}_w4`, name: 'Wall', type: 'Part', position: [x, 3, z+7], rotation: [0,0,0], scale: [15, 6, 1], color: '#e8e1d5', material: 'Plastic', transparency: 0, anchored: true, canCollide: true }, // Simple wall (no door logic for simplicity yet)
          // Roof
          { id: `${baseId}_roof`, name: 'Roof', type: 'Wedge', position: [x, 7.5, z], rotation: [0, Math.PI/4, 0], scale: [12, 4, 12], color: '#8b0000', material: 'Brick', transparency: 0, anchored: true, canCollide: true },
      ];
      setObjects([...objects, ...houseParts]);
  };

  const handlePlay = () => {
      if (isPlaying) {
          setIsPlaying(false);
      } else {
          setIsLoading(true);
          // Simulate Loading Time
          setTimeout(() => {
              setIsLoading(false);
              setIsPlaying(true);
          }, 3000);
      }
  };

  const handleUpdateObject = (id: string, newProps: Partial<MapObject>) => {
    setObjects(objects.map(obj => obj.id === id ? { ...obj, ...newProps } : obj));
  };

  const publishGame = () => {
      onPublish({ title: gameTitle, map: objects });
      setShowPublishModal(false);
      alert("¡Juego Publicado con Éxito!");
  };

  const selectedObject = objects.find(o => o.id === selectedId);

  return (
    <div className="flex flex-col h-screen w-screen bg-[#232527] overflow-hidden text-white font-sans relative">

      {/* Loading Screen Overlay */}
      {isLoading && <LoadingScreen />}

      {/* PUBLISH MODAL */}
      {showPublishModal && (
          <div className="absolute inset-0 z-50 bg-black/70 flex items-center justify-center">
              <div className="bg-[#2b2d31] p-6 rounded-lg w-96 border border-gray-600 shadow-xl">
                  <h2 className="text-xl font-bold mb-4">Publicar en Roblox</h2>
                  <label className="block text-xs text-gray-400 mb-1">Nombre de la Experiencia</label>
                  <input 
                    className="w-full bg-black/20 border border-gray-600 rounded p-2 mb-4 text-white" 
                    value={gameTitle} 
                    onChange={e => setGameTitle(e.target.value)}
                  />
                  <div className="flex gap-2 justify-end">
                      <button onClick={() => setShowPublishModal(false)} className="px-4 py-2 hover:bg-white/10 rounded text-sm">Cancelar</button>
                      <button onClick={publishGame} className="px-4 py-2 bg-[#00b06f] hover:bg-[#009e63] rounded text-sm font-bold">Publicar</button>
                  </div>
              </div>
          </div>
      )}

      {/* TOP TOOLBAR (Hidden when playing) */}
      {!isPlaying && (
        <div className="h-14 bg-[#2b2d31] border-b border-[#111213] flex items-center px-4 justify-between">
            <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
                <span className="font-bold text-[#00b06f]">ARCHIVO</span>
                <span className="font-bold text-gray-300">INICIO</span>
                <span className="text-gray-400">MODELO</span>
            </div>

            <div className="h-8 w-px bg-gray-600 mx-2"></div>

            <div className="flex gap-1 bg-[#1e1f21] p-1 rounded-lg">
                <button onClick={() => setTransformMode('translate')} className={`p-1.5 rounded ${transformMode === 'translate' ? 'bg-[#00a2ff]' : 'hover:bg-gray-700'}`}><Move size={18} /></button>
                <button onClick={() => setTransformMode('scale')} className={`p-1.5 rounded ${transformMode === 'scale' ? 'bg-[#00a2ff]' : 'hover:bg-gray-700'}`}><Maximize size={18} /></button>
                <button onClick={() => setTransformMode('rotate')} className={`p-1.5 rounded ${transformMode === 'rotate' ? 'bg-[#00a2ff]' : 'hover:bg-gray-700'}`}><RotateCw size={18} /></button>
            </div>

            <div className="h-8 w-px bg-gray-600 mx-2"></div>

            <div className="flex gap-2">
                <button onClick={() => handleAddObject('Part')} className="flex flex-col items-center justify-center p-1 hover:bg-white/10 rounded"><Box size={20} className="text-blue-400" /><span className="text-[10px]">Pieza</span></button>
                <button onClick={() => handleAddObject('Sphere')} className="flex flex-col items-center justify-center p-1 hover:bg-white/10 rounded"><Circle size={20} className="text-red-400" /><span className="text-[10px]">Esfera</span></button>
                <button onClick={() => handleAddObject('Wedge')} className="flex flex-col items-center justify-center p-1 hover:bg-white/10 rounded"><Triangle size={20} className="text-green-400" /><span className="text-[10px]">Cuña</span></button>
                <button onClick={() => handleAddObject('Cylinder')} className="flex flex-col items-center justify-center p-1 hover:bg-white/10 rounded"><Cylinder size={20} className="text-yellow-400 transform rotate-45" /><span className="text-[10px]">Cilindro</span></button>
                <div className="w-px bg-gray-600 h-8 mx-1"></div>
                <button onClick={handleAddHouse} className="flex flex-col items-center justify-center p-1 hover:bg-white/10 rounded"><Home size={20} className="text-orange-400" /><span className="text-[10px]">Casa RP</span></button>
            </div>
            </div>

            <div className="flex gap-2">
                <button onClick={() => setShowPublishModal(true)} className="flex items-center gap-2 bg-[#232527] border border-gray-600 hover:bg-gray-700 px-3 py-1.5 rounded text-sm font-bold">
                    <Save size={16} /> Publicar
                </button>
                <button onClick={handlePlay} className="flex items-center gap-2 bg-[#00b06f] hover:bg-[#009e63] px-4 py-1.5 rounded text-sm font-bold shadow-sm">
                    <Play size={16} fill="white" /> Jugar
                </button>
            </div>
        </div>
      )}

      {/* PLAY MODE HEADER */}
      {isPlaying && (
          <div className="absolute top-4 left-4 z-40">
              <button onClick={handlePlay} className="bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-4 rounded shadow-lg flex items-center gap-2">
                  <ArrowLeft size={20} /> Detener (Stop)
              </button>
          </div>
      )}

      {/* 3D WORKSPACE */}
      <div className="flex-1 flex overflow-hidden">

        <div className="flex-1 bg-[#111213] relative">
           <Canvas shadows dpr={[1, 2]}>
              {!isPlaying && <OrbitControls makeDefault />}

              <ambientLight intensity={0.5} />
              <directionalLight position={[50, 50, 25]} intensity={0.8} castShadow />

              {/* Sky / Environment */}
              <Sky sunPosition={[100, 20, 100]} turbidity={0.5} rayleigh={0.5} />
              <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

              {/* Editor Grid - Hide when playing */}
              {!isPlaying && <Grid infiniteGrid sectionSize={4} sectionColor="#6f6f6f" cellColor="#4a4a4a" position={[0, -0.01, 0]} />}

              {/* Player - Only when playing */}
              {isPlaying && <PlayerController avatarConfig={avatarConfig} mapObjects={objects} />}

              {/* Map Objects */}
              {objects.map((obj) => (
                <React.Fragment key={obj.id}>
                  {(selectedId === obj.id && !isPlaying) ? (
                    <TransformControls 
                      mode={transformMode} 
                      onObjectChange={(e: any) => {
                         if(e?.target?.object) {
                            const o = e.target.object;
                            handleUpdateObject(obj.id, {
                                position: [o.position.x, o.position.y, o.position.z],
                                rotation: [o.rotation.x, o.rotation.y, o.rotation.z],
                                scale: [o.scale.x, o.scale.y, o.scale.z]
                            });
                         }
                      }}
                    >
                       <mesh 
                        position={new THREE.Vector3(...obj.position)} 
                        rotation={new THREE.Euler(...obj.rotation)} 
                        scale={new THREE.Vector3(...obj.scale)}
                        onClick={(e) => { e.stopPropagation(); setSelectedId(obj.id); }}
                      >
                        <PartGeometry type={obj.type} />
                        {getMaterial(obj.material, obj.color)}
                      </mesh>
                    </TransformControls>
                  ) : (
                    <mesh 
                      position={new THREE.Vector3(...obj.position)} 
                      rotation={new THREE.Euler(...obj.rotation)} 
                      scale={new THREE.Vector3(...obj.scale)}
                      onClick={(e) => { 
                          if(!isPlaying) {
                            e.stopPropagation(); 
                            setSelectedId(obj.id); 
                          }
                      }}
                    >
                      <PartGeometry type={obj.type} />
                      {getMaterial(obj.material, obj.color)}
                    </mesh>
                  )}
                </React.Fragment>
              ))}

              {/* Deselect Plane */}
              {!isPlaying && (
                  <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -1, 0]} onClick={() => setSelectedId(null)}>
                    <planeGeometry args={[1000, 1000]} />
                    <meshBasicMaterial visible={false} />
                  </mesh>
              )}
           </Canvas>
        </div>

        {/* SIDEBARS - HIDE WHEN PLAYING */}
        {!isPlaying && (
            <div className="w-64 bg-[#2b2d31] border-l border-[#111213] flex flex-col">
                <div className="flex-1 border-b border-[#111213] overflow-hidden flex flex-col">
                    <div className="px-2 py-1 bg-[#36383c] text-xs font-bold text-gray-300">EXPLORADOR</div>
                    <div className="flex-1 overflow-y-auto p-1">
                        <div className="pl-1 text-sm text-gray-300">Workspace</div>
                        {objects.map(obj => (
                            <div key={obj.id} onClick={() => setSelectedId(obj.id)} className={`pl-4 cursor-pointer text-sm flex items-center gap-2 py-0.5 ${selectedId === obj.id ? 'bg-[#00a2ff] text-white' : 'text-gray-400 hover:text-white'}`}>
                                {obj.type === 'Part' && <Box size={12} />}
                                {obj.type === 'Sphere' && <Circle size={12} />}
                                {obj.name}
                            </div>
                        ))}
                    </div>
                </div>
                {/* Properties (Simplified) */}
                <div className="h-1/2 flex flex-col overflow-hidden">
                    <div className="px-2 py-1 bg-[#36383c] text-xs font-bold text-gray-300">PROPIEDADES</div>
                    {selectedObject && (
                        <div className="p-2 space-y-2 overflow-y-auto">
                            <label className="text-xs text-gray-500">Nombre</label>
                            <input value={selectedObject.name} onChange={(e) => handleUpdateObject(selectedObject.id, {name: e.target.value})} className="w-full bg-[#1e1f21] border border-gray-600 text-xs p-1" />
                            <label className="text-xs text-gray-500">Color</label>
                            <input type="color" value={selectedObject.color} onChange={(e) => handleUpdateObject(selectedObject.id, {color: e.target.value})} className="w-full h-6 bg-transparent" />
                            <label className="text-xs text-gray-500">Material</label>
                            <select value={selectedObject.material} onChange={(e) => handleUpdateObject(selectedObject.id, {material: e.target.value as any})} className="w-full bg-[#1e1f21] border border-gray-600 text-xs p-1">
                                <option>Plastic</option><option>Neon</option><option>Wood</option><option>Brick</option>
                            </select>
                        </div>
                    )}
                </div>
            </div>
        )}
      </div>
      <div className="h-6 bg-[#007acc] flex items-center px-2 justify-between text-xs text-white">
         <span>{isPlaying ? 'JUGANDO' : 'LISTO'}</span>
         <span>Partes: {objects.length}</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { HashRouter } from 'react-router-dom';
import { LoginPage } from './pages/Login';
import { HomePage } from './pages/Home';
import { Navbar } from './components/Navbar';
import { Sidebar } from './components/Sidebar';
import { User, Page, AvatarConfig, Game, MapObject } from './types';
import { AvatarScene } from './components/AvatarScene';
import { AvatarEditor } from './pages/AvatarEditor';
import { StudioPage } from './pages/Studio';
import { GameCard } from './components/GameCard'; // Assuming this exists from previous files

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [sidebarOpen, setSidebarOpen] = useState<boolean>(true);
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [user, setUser] = useState<User | null>(null);

  // Published Games State
  const [publishedGames, setPublishedGames] = useState<Game[]>([
      { id: '1', title: 'Brookhaven RP [Clone]', creator: 'Roblox', thumbnail: 'https://via.placeholder.com/400/004400/FFFFFF?text=Brookhaven', likes: '94%', playing: 450000 },
      { id: '2', title: 'Tower of Hell', creator: 'User123', thumbnail: 'https://via.placeholder.com/400/990000/FFFFFF?text=Tower', likes: '88%', playing: 12000 }
  ]);

  // Avatar Configuration State
  const [avatarConfig, setAvatarConfig] = useState<AvatarConfig>({
    bodyColors: {
      head: '#F5CD30',
      torso: '#0047AB',
      leftArm: '#F5CD30',
      rightArm: '#F5CD30',
      leftLeg: '#A2C429',
      rightLeg: '#A2C429'
    },
    faceTextureUrl: null,
    accessories: { hatModelUrl: null, shirtTextureUrl: null },
    hideFace: false
  });

  useEffect(() => {
    const storedUser = localStorage.getItem('robloxCloneUser');
    if (storedUser) {
        setUser(JSON.parse(storedUser));
        setIsAuthenticated(true);
    }
  }, []);

  const handleLogin = (username: string) => {
    const newUser = {
      username: username,
      displayName: username,
      robux: 1540
    };
    setUser(newUser);
    localStorage.setItem('robloxCloneUser', JSON.stringify(newUser));
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('robloxCloneUser');
    setIsAuthenticated(false);
    setCurrentPage(Page.HOME);
  };

  const handlePublishGame = (gameData: { title: string, map: MapObject[] }) => {
      const newGame: Game = {
          id: Date.now().toString(),
          title: gameData.title,
          creator: user?.displayName || 'Anon',
          thumbnail: 'https://via.placeholder.com/400/0000FF/FFFFFF?text=' + gameData.title.substring(0,3), // Placeholder thumb
          likes: '0%',
          playing: 0,
          mapData: gameData.map
      };
      setPublishedGames([newGame, ...publishedGames]);
  };

  if (!isAuthenticated) {
    return <LoginPage onLogin={handleLogin} />;
  }

  // STUDIO Page Override
  if (currentPage === Page.STUDIO) {
      return (
        <div className="h-screen w-screen bg-[#232527]">
           <button 
             onClick={() => setCurrentPage(Page.HOME)}
             className="fixed top-3 right-3 z-50 bg-red-600 hover:bg-red-700 text-white px-3 py-1 text-xs rounded shadow-md"
           >
             Salir de Studio
           </button>
           <StudioPage onPublish={handlePublishGame} avatarConfig={avatarConfig} />
        </div>
      );
  }

  return (
    <HashRouter>
      <div className="min-h-screen bg-[#232527] flex flex-col font-sans">
        {user && (
            <Navbar 
                user={user} 
                onToggleSidebar={() => setSidebarOpen(!sidebarOpen)}
                onLogout={handleLogout}
            />
        )}

        <div className="flex flex-1 pt-[0px] relative">
          <Sidebar 
            isOpen={sidebarOpen} 
            currentPage={currentPage} 
            onNavigate={setCurrentPage}
            userName={user?.displayName || 'Guest'}
          />

          <main 
            className={`flex-1 transition-all duration-300 ${sidebarOpen ? 'md:ml-64' : 'md:ml-16'} ml-0`}
          >
            {currentPage === Page.HOME && user && (
              <div className="p-6 md:p-8 max-w-[1600px] mx-auto">
                 <div className="flex flex-col md:flex-row gap-8 mb-10">
                    <div className="flex-1">
                        <h1 className="text-3xl md:text-4xl font-bold text-white mb-2">Inicio</h1>
                        <p className="text-gray-400 text-lg">Hola, <span className="text-white font-bold">{user.displayName}</span></p>
                    </div>
                 </div>

                 <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 mb-12">
                     <div className="lg:col-span-1 bg-[#2b2d31] p-4 rounded-xl border border-[#393b3d] flex flex-col items-center">
                          <h3 className="text-white font-bold self-start mb-4">Tu Avatar</h3>
                          <div className="w-full aspect-[3/4] rounded-lg overflow-hidden relative">
                              {/* Small overlay to show "3D" */}
                              <div className="absolute top-2 right-2 bg-black/50 px-2 py-1 rounded text-[10px] z-10 font-bold">R15</div>
                              <AvatarScene config={avatarConfig} interactive={false} />
                          </div>
                          <button 
                            onClick={() => setCurrentPage(Page.AVATAR)}
                            className="mt-4 w-full bg-white/10 hover:bg-white/20 py-2 rounded-lg font-medium text-sm transition-colors text-white"
                          >
                              Personalizar
                          </button>
                     </div>

                     <div className="lg:col-span-3">
                         <h3 className="text-xl font-bold text-white mb-4">Experiencias Recomendadas</h3>
                         <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                             {publishedGames.map(game => (
                                 <div key={game.id} onClick={() => alert("Para jugar, ve a 'Crear' y pulsa Jugar dentro del Editor para probar la física completa.")}>
                                     <GameCard game={game} />
                                 </div>
                             ))}
                         </div>
                     </div>
                 </div>
              </div>
            )}

            {currentPage === Page.PROFILE && (
                <div className="flex flex-col items-center justify-center h-full min-h-[500px] text-gray-400">
                    <h2 className="text-2xl font-bold text-white mb-4">Perfil de Usuario</h2>
                    <div className="w-64 h-64">
                         <AvatarScene config={avatarConfig} />
                    </div>
                </div>
            )}

            {currentPage === Page.AVATAR && (
                <div className="p-4 md:p-8 max-w-6xl mx-auto h-[calc(100vh-60px)] flex flex-col">
                     <div className="flex justify-between items-center mb-4">
                        <h2 className="text-3xl font-bold text-white">Editor de Avatar</h2>
                     </div>
                     <div className="flex-1 flex flex-col md:flex-row gap-4 overflow-hidden">
                        <div className="flex-1 bg-[#111213] rounded-xl border border-[#393b3d] relative overflow-hidden shadow-2xl">
                             <AvatarScene config={avatarConfig} />
                        </div>
                        <div className="w-full md:w-[400px] bg-[#232527] rounded-xl border border-[#393b3d] overflow-hidden flex flex-col shadow-xl">
                            <AvatarEditor 
                              currentConfig={avatarConfig} 
                              onUpdateConfig={setAvatarConfig} 
                            />
                        </div>
                     </div>
                </div>
            )}

            {currentPage === Page.GAMES && (
                 <div className="p-8">
                     <h2 className="text-2xl font-bold text-white mb-6">Todas las Experiencias</h2>
                     <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
                         {publishedGames.map(game => (
                             <GameCard key={game.id} game={game} />
                         ))}
                     </div>
                 </div>
            )}
          </main>
        </div>
      </div>
    </HashRouter>
  );
}

export default App;

export interface User {
  username: string;
  displayName: string;
  robux: number;
  avatarUrl?: string; 
}

export interface MapObject {
  id: string;
  name: string;
  type: 'Part' | 'Sphere' | 'Wedge' | 'Cylinder' | 'Model';
  position: [number, number, number];
  rotation: [number, number, number];
  scale: [number, number, number];
  color: string;
  material: 'Plastic' | 'Neon' | 'Grass' | 'Wood' | 'Brick' | 'Fabric';
  transparency: number;
  anchored: boolean;
  canCollide: boolean;
  assetUrl?: string; // For imported models (Blob URL)
}

export interface Game {
  id: string;
  title: string;
  creator: string;
  thumbnail: string;
  likes: string;
  playing: number;
  mapData?: MapObject[]; // Saved map state
}

export interface AvatarConfig {
  bodyColors: {
    head: string;
    torso: string;
    leftArm: string;
    rightArm: string;
    leftLeg: string;
    rightLeg: string;
  };
  faceTextureUrl: string | null; // URL string (blob or http)
  accessories: {
    hatModelUrl: string | null; // URL string for .glb/.gltf
    shirtTextureUrl: string | null;
  };
  hideFace: boolean;
}

export interface StoreItem {
  id: string;
  name: string;
  type: 'face' | 'hat' | 'shirt';
  price: number; // 0 for free
  thumbnail: string; // URL or placeholder
  assetUrl: string; // The actual content
  creator: string;
}

export enum Page {
  HOME = 'HOME',
  PROFILE = 'PROFILE',
  GAMES = 'GAMES',
  AVATAR = 'AVATAR',
  STORE = 'STORE',
  STUDIO = 'STUDIO',
  PLAY = 'PLAY' // New page for playing games
}

import React, { useRef, useState, useEffect } from 'react';
import { Canvas, useFrame, useLoader } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, ContactShadows, Environment, useGLTF } from '@react-three/drei';
import * as THREE from 'three';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader';
import { AvatarConfig } from '../types';

// Helper component to load external GLTF/GLB models
const AccessoryModel = ({ url, position, scale }: { url: string; position: any; scale: any }) => {
  const { scene } = useGLTF(url);
  const clone = React.useMemo(() => scene.clone(), [scene]);
  return <primitive object={clone} position={position} scale={scale} />;
};

