// --- GAME CONTROLS UI (JOYSTICK) ---
const GameControls = () => {
    const joystickRef = useRef<HTMLDivElement>(null);
    const [active, setActive] = useState(false);

    const handleStart = (e: React.PointerEvent) => {
        setActive(true);
        handleMove(e);
    };

    const handleMove = (e: React.PointerEvent) => {
        if (!active || !joystickRef.current) return;
        const rect = joystickRef.current.parentElement!.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;

        let dx = (e.clientX - centerX) / (rect.width / 2);
        let dy = (centerY - e.clientY) / (rect.height / 2); // Inverted Y for forward

        // Clamp
        const dist = Math.sqrt(dx*dx + dy*dy);
        if (dist > 1) {
            dx /= dist;
            dy /= dist;
        }

        // Move the stick visually
        joystickRef.current.style.transform = `translate(${dx * 40}px, ${-dy * 40}px)`;

        // Dispatch Event
        window.dispatchEvent(new CustomEvent('joystickMove', { detail: { x: dx, y: dy } }));
    };

    const handleEnd = () => {
        setActive(false);
        if (joystickRef.current) joystickRef.current.style.transform = `translate(0px, 0px)`;
        window.dispatchEvent(new CustomEvent('joystickMove', { detail: { x: 0, y: 0 } }));
    };

    return (
        <div className="absolute inset-0 pointer-events-none z-40 select-none">
            {/* Left Joystick */}
            <div 
                className="absolute bottom-10 left-10 w-32 h-32 bg-white/10 rounded-full border-2 border-white/30 backdrop-blur-sm pointer-events-auto flex items-center justify-center touch-none"
                onPointerDown={handleStart}
                onPointerMove={handleMove}
                onPointerUp={handleEnd}
                onPointerLeave={handleEnd}
            >
                <div ref={joystickRef} className="w-12 h-12 bg-white/50 rounded-full shadow-lg" />
            </div>

            {/* Right Jump Button */}
            <div 
                className="absolute bottom-10 right-10 w-24 h-24 bg-white/10 rounded-full border-2 border-white/30 backdrop-blur-sm pointer-events-auto flex items-center justify-center active:bg-white/30 transition-colors cursor-pointer touch-none"
                onPointerDown={() => window.dispatchEvent(new Event('jumpPress'))}
                onPointerUp={() => window.dispatchEvent(new Event('jumpRelease'))}
            >
                <div className="w-16 h-16 bg-[url('https://upload.wikimedia.org/wikipedia/commons/thumb/e/e0/Arrow_up_font_awesome.svg/1024px-Arrow_up_font_awesome.svg.png')] bg-cover opacity-50 filter invert" />
            </div>
        </div>
    );
};

