                <div className="flex items-center gap-2"><span className="font-bold text-[#00b06f]">ARCHIVO</span><span className="font-bold text-gray-300">INICIO</span></div>
                <div className="flex gap-1 bg-[#1e1f21] p-1 rounded-lg">
