      const url = URL.createObjectURL(file);
      if (type === 'face') {
        onUpdateConfig({ ...currentConfig, faceTextureUrl: url, hideFace: false });
      } else if (type === 'hat') {
        const isFbx = file.name.toLowerCase().endsWith('.fbx');
