export const StudioPage: React.FC<StudioProps> = ({ onPublish, avatarConfig, initialMapData, isPlayMode = false, activeServer, onExit, playerName }) => {
  const [objects, setObjects] = useState<MapObject[]>(initialMapData || INITIAL_MAP);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [transformMode, setTransformMode] = useState<'translate' | 'rotate' | 'scale'>('translate');
  const [isPlaying, setIsPlaying] = useState(false); 
  const [loadingStep, setLoadingStep] = useState(0);
  const [showPublishModal, setShowPublishModal] = useState(false);
  const [gameTitle, setGameTitle] = useState("Mi Juego de Roblox");

  // Multiplayer State
  const [remotePlayers, setRemotePlayers] = useState<RemotePlayer[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
      if (isPlayMode) {
          handlePlaySequence();
          // Simulate Joining Server if activeServer is present
          if (activeServer) {
              console.log(`Joined server: ${activeServer.name} with ${activeServer.players} players.`);
              simulateMultiplayer(activeServer.players);
          }
      }
  }, [isPlayMode, activeServer]);

  // --- MULTIPLAYER SIMULATION ---
  const simulateMultiplayer = (count: number) => {
      const bots: RemotePlayer[] = [];
      const names = ["xX_Gamer_Xx", "NoobMaster69", "BuilderMan", "RobloxQueen", "CoolKid2025", "Guest_999", "ProGamer_YT"];

      const getRandomColor = () => '#' + Math.floor(Math.random()*16777215).toString(16);

      for (let i = 0; i < Math.min(count, 10); i++) {
          bots.push({
              id: `bot-${i}`,
              username: names[i % names.length],
              position: [(Math.random() - 0.5) * 30, 2, (Math.random() - 0.5) * 30],
              rotation: [0, Math.random() * Math.PI * 2, 0],
              isMoving: false,
              isJumping: false,
              targetPosition: [(Math.random() - 0.5) * 30, 2, (Math.random() - 0.5) * 30],
              config: {
                  bodyColors: {
                      head: '#F5CD30', torso: getRandomColor(), leftArm: '#F5CD30', rightArm: '#F5CD30', leftLeg: '#A2C429', rightLeg: '#A2C429'
                  },
                  faceTextureUrl: null, accessories: { hatModelUrl: null, shirtTextureUrl: null }, hideFace: false
              }
          });
      }
      setRemotePlayers(bots);
  };

  // Move remote players loop
  useEffect(() => {
      if (!isPlaying || remotePlayers.length === 0) return;

      const interval = setInterval(() => {
           setRemotePlayers(current => current.map(p => {
               // Simple random walk logic
               if (Math.random() > 0.95) {
                   // Pick new target
                   return {
                       ...p,
                       targetPosition: [(Math.random() - 0.5) * 40, 2, (Math.random() - 0.5) * 40],
                       isMoving: true
                   };
               }
               return p;
           }));
      }, 1000);

      return () => clearInterval(interval);
  }, [isPlaying, remotePlayers.length]);

  const handlePlaySequence = () => {
      setLoadingStep(1);
      const sequence = [
          () => setLoadingStep(1),
          () => setLoadingStep(2),
          () => setLoadingStep(3),
          () => { setLoadingStep(4); setTimeout(() => setIsPlaying(true), 800); }
      ];
      let i = 0;
      const interval = setInterval(() => {
          if (i < sequence.length) { sequence[i](); i++; } 
          else { clearInterval(interval); }
      }, 800);
  };

  const handleImportModel = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const isFbx = file.name.toLowerCase().endsWith('.fbx');
    const url = URL.createObjectURL(file);
    const newObj: MapObject = {
        id: Date.now().toString(),
        name: file.name,
        type: 'Model',
        position: [0, 2, 0],
        rotation: [0, 0, 0],
        scale: [1, 1, 1],
        color: '#ffffff',
        material: 'Plastic',
        transparency: 0,
        anchored: false,
        canCollide: true,
        assetUrl: isFbx ? url + '#fbx' : url,
    };
    setObjects([...objects, newObj]);
    setSelectedId(newObj.id);
  };

  const handleUpdateObject = (id: string, newProps: Partial<MapObject>) => {
    setObjects(objects.map(obj => obj.id === id ? { ...obj, ...newProps } : obj));
  };

  const RenderMap = () => (
      <>
        {objects.map((obj) => (
            <React.Fragment key={obj.id}>
                {(selectedId === obj.id && !isPlaying) ? (
                <TransformControls 
                    mode={transformMode} 
                    onObjectChange={(e: any) => {
                        if(e?.target?.object) {
                            const o = e.target.object;
                            handleUpdateObject(obj.id, {
                                position: [o.position.x, o.position.y, o.position.z],
                                rotation: [o.rotation.x, o.rotation.y, o.rotation.z],
                                scale: [o.scale.x, o.scale.y, o.scale.z]
                            });
                        }
                    }}
                >
                    <mesh 
                        position={new THREE.Vector3(...obj.position)} 
                        rotation={new THREE.Euler(...obj.rotation)} 
                        scale={new THREE.Vector3(...obj.scale)}
                        onClick={(e) => { e.stopPropagation(); setSelectedId(obj.id); }}
                    >
                        {obj.type === 'Model' && obj.assetUrl ? (
                            <Suspense fallback={<mesh><boxGeometry args={[1,1,1]} /><meshStandardMaterial color="gray" wireframe /></mesh>}>
                                <ImportedModel url={obj.assetUrl.replace('#fbx','')} isFbx={obj.assetUrl.includes('#fbx')} />
                            </Suspense>
                        ) : (
                            <>
                                <PartGeometry type={obj.type} />
                                {getMaterial(obj.material, obj.color)}
                            </>
                        )}
                    </mesh>
                </TransformControls>
                ) : (
                <mesh 
                    position={new THREE.Vector3(...obj.position)} 
                    rotation={new THREE.Euler(...obj.rotation)} 
                    scale={new THREE.Vector3(...obj.scale)}
                    onClick={(e) => { 
                        if(!isPlaying) {
                            e.stopPropagation(); 
                            setSelectedId(obj.id); 
                        }
                    }}
                >
                    {obj.type === 'Model' && obj.assetUrl ? (
                            <Suspense fallback={<mesh><boxGeometry args={[1,1,1]} /><meshStandardMaterial color="gray" wireframe /></mesh>}>
                                <ImportedModel url={obj.assetUrl.replace('#fbx','')} isFbx={obj.assetUrl.includes('#fbx')} />
                            </Suspense>
                        ) : (
                            <>
                                <PartGeometry type={obj.type} />
                                {getMaterial(obj.material, obj.color)}
                            </>
                        )}
                </mesh>
                )}
            </React.Fragment>
        ))}
      </>
  );

  // Component to interpolate remote players
  const RemotePlayerRenderer = ({ player }: { player: RemotePlayer }) => {
      const groupRef = useRef<THREE.Group>(null);
      const [currentPos, setCurrentPos] = useState(new THREE.Vector3(...player.position));
      const [currentRot, setCurrentRot] = useState(new THREE.Euler(...player.rotation));

      useFrame((state, delta) => {
          if (player.targetPosition && player.isMoving) {
               const target = new THREE.Vector3(...player.targetPosition);
               currentPos.lerp(target, delta * 0.5); // Smooth walk

               // Look at target
               if (currentPos.distanceTo(target) > 0.5) {
                   const angle = Math.atan2(target.x - currentPos.x, target.z - currentPos.z);
                   currentRot.y = angle + Math.PI; // Face the right way
               }
          }
      });

      return (
          <RobloxCharacter 
             config={player.config} 
             position={[currentPos.x, currentPos.y, currentPos.z]} 
             rotation={[0, currentRot.y, 0]}
             isMoving={player.isMoving}
             username={player.username}
          />
      );
  }

  return (
    <div className="flex flex-col h-screen w-screen bg-[#232527] overflow-hidden text-white font-sans relative">

      {loadingStep > 0 && !isPlaying && <LoadingScreen loadingStep={loadingStep} />}

      {isPlaying && <GameControls />}

      {showPublishModal && (
          <div className="absolute inset-0 z-50 bg-black/70 flex items-center justify-center">
              <div className="bg-[#2b2d31] p-6 rounded-lg w-96 border border-gray-600 shadow-xl">
                  <h2 className="text-xl font-bold mb-4">Publicar en Roblox</h2>
                  <input className="w-full bg-black/20 border border-gray-600 rounded p-2 mb-4" value={gameTitle} onChange={e => setGameTitle(e.target.value)} />
                  <div className="flex gap-2 justify-end">
                      <button onClick={() => setShowPublishModal(false)} className="px-4 py-2 hover:bg-white/10 rounded">Cancelar</button>
                      <button onClick={() => { onPublish({ title: gameTitle, map: objects }); setShowPublishModal(false); alert("¡Juego Publicado!"); }} className="px-4 py-2 bg-[#00b06f] rounded font-bold">Publicar</button>
                  </div>
              </div>
          </div>
      )}

      {!isPlaying && !isPlayMode && (
        <div className="h-14 bg-[#2b2d31] border-b border-[#111213] flex items-center px-4 justify-between">
            <div className="flex items-center gap-6">
                <div className="flex items-center gap-2"><span className="font-bold text-[#00b06f]">ARCHIVO</span><span className="font-bold text-gray-300">INICIO</span></div>
                <div className="flex gap-1 bg-[#1e1f21] p-1 rounded-lg">
                    <button onClick={() => setTransformMode('translate')} className={`p-1.5 rounded ${transformMode === 'translate' ? 'bg-[#00a2ff]' : 'hover:bg-gray-700'}`}><Move size={18} /></button>
                    <button onClick={() => setTransformMode('scale')} className={`p-1.5 rounded ${transformMode === 'scale' ? 'bg-[#00a2ff]' : 'hover:bg-gray-700'}`}><Maximize size={18} /></button>
                    <button onClick={() => setTransformMode('rotate')} className={`p-1.5 rounded ${transformMode === 'rotate' ? 'bg-[#00a2ff]' : 'hover:bg-gray-700'}`}><RotateCw size={18} /></button>
                </div>
                <div className="flex gap-2">
                    <button onClick={() => { 
                         const newObj: MapObject = { id: Date.now().toString(), name: 'Part', type: 'Part', position: [0, 5, 0], rotation: [0,0,0], scale: [1,1,1], color: '#A2A2A2', material: 'Plastic', transparency: 0, anchored: false, canCollide: true };
                         setObjects([...objects, newObj]); setSelectedId(newObj.id);
                    }} className="p-1 hover:bg-white/10 rounded"><BoxIcon size={20} className="text-blue-400" /></button>
                    <button onClick={() => { 
                         const newObj: MapObject = { id: Date.now().toString(), name: 'Sphere', type: 'Sphere', position: [0, 5, 0], rotation: [0,0,0], scale: [1,1,1], color: '#A2A2A2', material: 'Plastic', transparency: 0, anchored: false, canCollide: true };
                         setObjects([...objects, newObj]); setSelectedId(newObj.id);
                    }} className="p-1 hover:bg-white/10 rounded"><CircleIcon size={20} className="text-red-400" /></button>
                    <button onClick={() => { 
                         const newObj: MapObject = { id: Date.now().toString(), name: 'Wedge', type: 'Wedge', position: [0, 5, 0], rotation: [0,0,0], scale: [1,1,1], color: '#A2A2A2', material: 'Plastic', transparency: 0, anchored: false, canCollide: true };
                         setObjects([...objects, newObj]); setSelectedId(newObj.id);
                    }} className="p-1 hover:bg-white/10 rounded"><TriangleIcon size={20} className="text-green-400" /></button>
                    <button onClick={() => { 
                         const newObj: MapObject = { id: Date.now().toString(), name: 'Cylinder', type: 'Cylinder', position: [0, 5, 0], rotation: [0,0,0], scale: [1,1,1], color: '#A2A2A2', material: 'Plastic', transparency: 0, anchored: false, canCollide: true };
                         setObjects([...objects, newObj]); setSelectedId(newObj.id);
                    }} className="p-1 hover:bg-white/10 rounded"><CylinderIcon size={20} className="text-yellow-400 transform rotate-45" /></button>

                    <input type="file" ref={fileInputRef} hidden accept=".glb,.gltf,.fbx" onChange={handleImportModel} />
                    <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center justify-center p-1 hover:bg-white/10 rounded">
                        <Upload size={20} className="text-purple-400" />
                        <span className="text-[10px]">Importar 3D</span>
                    </button>
                </div>
            </div>
            <div className="flex gap-2">
                <button onClick={() => setShowPublishModal(true)} className="flex items-center gap-2 bg-[#232527] border border-gray-600 hover:bg-gray-700 px-3 py-1.5 rounded text-sm font-bold"><Save size={16} /> Publicar</button>
                <button onClick={handlePlaySequence} className="flex items-center gap-2 bg-[#00b06f] hover:bg-[#009e63] px-4 py-1.5 rounded text-sm font-bold shadow-sm"><Play size={16} fill="white" /> Jugar</button>
            </div>
        </div>
      )}

      {/* STOP BUTTON / SERVER INFO */}
      {isPlaying && (
          <div className="absolute top-4 left-4 z-50 flex flex-col gap-2">
              <button onClick={() => { 
                  if (isPlayMode && onExit) onExit();
                  else { setIsPlaying(false); setLoadingStep(0); }
              }} className="bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-4 rounded shadow-lg flex items-center gap-2 border-2 border-white/20">
                  <ArrowLeft size={20} /> {isPlayMode ? 'Salir del Juego' : 'Detener'}
              </button>
              {activeServer && (
                  <div className="bg-black/50 p-2 rounded text-xs text-white border border-white/10 backdrop-blur-md">
                      <div className="font-bold text-green-400">● Conectado</div>
                      <div>{activeServer.name}</div>
                      <div>Ping: {activeServer.ping}ms</div>
                  </div>
              )}
          </div>
      )}

      <div className="flex-1 flex overflow-hidden">
        <div className="flex-1 bg-[#111213] relative">
           <Canvas shadows dpr={[1, 2]}>
              {!isPlaying && <OrbitControls makeDefault />}
              <ambientLight intensity={0.5} />
              <directionalLight position={[50, 50, 25]} intensity={0.8} castShadow />
              <Sky sunPosition={[100, 20, 100]} turbidity={0.5} rayleigh={0.5} />
              <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />
              {!isPlaying && <Grid infiniteGrid sectionSize={4} sectionColor="#6f6f6f" cellColor="#4a4a4a" position={[0, -0.01, 0]} />}

              {isPlaying && <PlayerController avatarConfig={avatarConfig} mapObjects={objects} username={playerName} />}

              {/* RENDER REMOTE PLAYERS */}
              {isPlaying && remotePlayers.map(rp => (
                  <RemotePlayerRenderer key={rp.id} player={rp} />
              ))}

              <RenderMap />

              {!isPlaying && (
                  <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -1, 0]} onClick={() => setSelectedId(null)}>
                    <planeGeometry args={[1000, 1000]} />
                    <meshBasicMaterial visible={false} />
                  </mesh>
              )}
           </Canvas>
        </div>

        {!isPlaying && !isPlayMode && (
            <div className="w-64 bg-[#2b2d31] border-l border-[#111213] flex flex-col">
                <div className="flex-1 overflow-y-auto p-2">
                    <div className="text-xs font-bold text-gray-300 mb-2">EXPLORADOR</div>
                    {objects.map(obj => (
                        <div key={obj.id} onClick={() => setSelectedId(obj.id)} className={`pl-2 cursor-pointer text-sm flex items-center gap-2 py-0.5 ${selectedId === obj.id ? 'bg-[#00a2ff] text-white' : 'text-gray-400'}`}>
                            {obj.type === 'Model' ? <FileBox size={12}/> : <BoxIcon size={12} />} {obj.name}
                        </div>
                    ))}
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { HashRouter } from 'react-router-dom';
import { LoginPage } from './pages/Login';
import { Navbar } from './components/Navbar';
import { Sidebar } from './components/Sidebar';
import { User, Page, AvatarConfig, Game, MapObject, Server } from './types';
import { AvatarScene } from './components/AvatarScene';
import { AvatarEditor } from './pages/AvatarEditor';
import { StudioPage } from './pages/Studio';
import { GameCard } from './components/GameCard';
import { Play, ThumbsUp, User as UserIcon, Server as ServerIcon, Plus } from 'lucide-react';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [sidebarOpen, setSidebarOpen] = useState<boolean>(true);
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [user, setUser] = useState<User | null>(null);

  // Game Play State
  const [selectedGame, setSelectedGame] = useState<Game | null>(null);

  // Initial Games
  const [publishedGames, setPublishedGames] = useState<Game[]>([
      { id: '1', title: 'Brookhaven RP [Clone]', creator: 'Roblox', thumbnail: 'https://tr.rbxcdn.com/c7895e63415714755106192131238497/768/432/Image/Png', likes: '94%', playing: 450000, mapData: undefined },
      { id: '2', title: 'Tower of Hell', creator: 'User123', thumbnail: 'https://tr.rbxcdn.com/a4db2969989a30283f36a53603d7c24f/768/432/Image/Png', likes: '88%', playing: 12000, mapData: undefined }
  ]);

  const [avatarConfig, setAvatarConfig] = useState<AvatarConfig>({
    bodyColors: {
      head: '#F5CD30', torso: '#0047AB', leftArm: '#F5CD30', rightArm: '#F5CD30', leftLeg: '#A2C429', rightLeg: '#A2C429'
    },
    faceTextureUrl: null,
    accessories: { hatModelUrl: null, shirtTextureUrl: null },
    hideFace: false
  });

  useEffect(() => {
    const storedUser = localStorage.getItem('robloxCloneUser');
    if (storedUser) {
        setUser(JSON.parse(storedUser));
        setIsAuthenticated(true);
    }
  }, []);

  const handleLogin = (username: string) => {
    const newUser = { username: username, displayName: username, robux: 1540 };
    setUser(newUser);
    localStorage.setItem('robloxCloneUser', JSON.stringify(newUser));
    setIsAuthenticated(true);
  };

  const handlePublishGame = (gameData: { title: string, map: MapObject[] }) => {
      const newGame: Game = {
          id: Date.now().toString(),
          title: gameData.title,
          creator: user?.displayName || 'Anon',
          thumbnail: 'https://tr.rbxcdn.com/530e542ef9983424075f9227653606db/768/432/Image/Png', // Generic thumb
          likes: '0%',
          playing: 0,
          mapData: gameData.map
      };
      setPublishedGames([newGame, ...publishedGames]);
  };

  const openGameDetails = (game: Game) => {
      setSelectedGame(game);
      setCurrentPage(Page.PLAY);
  };

  if (!isAuthenticated) return <LoginPage onLogin={handleLogin} />;

  // --- STUDIO MODE ---
  if (currentPage === Page.STUDIO) {
      return (
        <div className="h-screen w-screen bg-[#232527]">
           <button onClick={() => setCurrentPage(Page.HOME)} className="fixed top-3 right-3 z-50 bg-red-600 hover:bg-red-700 text-white px-3 py-1 text-xs rounded shadow-md">Salir</button>
           <StudioPage onPublish={handlePublishGame} avatarConfig={avatarConfig} />
        </div>
      );
  }

  // --- GAME PLAY MODE (LAUNCHER) ---
  if (currentPage === Page.PLAY && selectedGame && user) {
      return <GamePlayerView game={selectedGame} avatarConfig={avatarConfig} onBack={() => setCurrentPage(Page.HOME)} user={user} />;
  }

  return (
    <HashRouter>
      <div className="min-h-screen bg-[#232527] flex flex-col font-sans">
        {user && <Navbar user={user} onToggleSidebar={() => setSidebarOpen(!sidebarOpen)} onLogout={() => { setUser(null); setIsAuthenticated(false); }} />}

        <div className="flex flex-1 pt-[0px] relative">
          <Sidebar isOpen={sidebarOpen} currentPage={currentPage} onNavigate={setCurrentPage} userName={user?.displayName || 'Guest'} />

          <main className={`flex-1 transition-all duration-300 ${sidebarOpen ? 'md:ml-64' : 'md:ml-16'} ml-0`}>
            {currentPage === Page.HOME && user && (
              <div className="p-6 md:p-8 max-w-[1600px] mx-auto">
                 <div className="flex flex-col md:flex-row gap-8 mb-10">
                    <div className="flex-1">
                        <h1 className="text-3xl md:text-4xl font-bold text-white mb-2">Inicio</h1>
                        <p className="text-gray-400 text-lg">Hola, <span className="text-white font-bold">{user.displayName}</span></p>
                    </div>
                 </div>
                 <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 mb-12">
                     <div className="lg:col-span-1 bg-[#2b2d31] p-4 rounded-xl border border-[#393b3d] flex flex-col items-center">
                          <div className="w-full aspect-[3/4] rounded-lg overflow-hidden relative">
                              <AvatarScene config={avatarConfig} interactive={false} />
                          </div>
                          <button onClick={() => setCurrentPage(Page.AVATAR)} className="mt-4 w-full bg-white/10 hover:bg-white/20 py-2 rounded-lg font-medium text-sm transition-colors text-white">Personalizar</button>
                     </div>
                     <div className="lg:col-span-3">
                         <h3 className="text-xl font-bold text-white mb-4">Experiencias</h3>
                         <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                             {publishedGames.map(game => (
                                 <div key={game.id} onClick={() => openGameDetails(game)}>
                                     <GameCard game={game} />
                                 </div>
                             ))}
                         </div>
                     </div>
                 </div>
              </div>
            )}

            {currentPage === Page.PROFILE && (
                <div className="flex flex-col items-center justify-center h-full min-h-[500px] text-gray-400">
                    <h2 className="text-2xl font-bold text-white mb-4">Perfil</h2>
                    <div className="w-64 h-64"><AvatarScene config={avatarConfig} /></div>
                </div>
            )}

            {currentPage === Page.AVATAR && (
                <div className="p-4 md:p-8 max-w-6xl mx-auto h-[calc(100vh-60px)] flex flex-col">
                     <div className="flex-1 flex flex-col md:flex-row gap-4 overflow-hidden">
                        <div className="flex-1 bg-[#111213] rounded-xl border border-[#393b3d] relative overflow-hidden shadow-2xl"><AvatarScene config={avatarConfig} /></div>
                        <div className="w-full md:w-[400px] bg-[#232527] rounded-xl border border-[#393b3d] overflow-hidden flex flex-col shadow-xl"><AvatarEditor currentConfig={avatarConfig} onUpdateConfig={setAvatarConfig} /></div>
                     </div>
                </div>
            )}

            {currentPage === Page.GAMES && (
                 <div className="p-8">
                     <h2 className="text-2xl font-bold text-white mb-6">Todas las Experiencias</h2>
                     <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
                         {publishedGames.map(game => <div key={game.id} onClick={() => openGameDetails(game)}><GameCard game={game} /></div>)}
                     </div>
                 </div>
            )}
          </main>
        </div>
      </div>
    </HashRouter>
  );
}

// --- SUB-COMPONENT: GAME DETAILS & PLAYER ---
const GamePlayerView = ({ game, avatarConfig, onBack, user }: { game: Game, avatarConfig: AvatarConfig, onBack: () => void, user: User }) => {
    const [isPlaying, setIsPlaying] = useState(false);
    const [activeServer, setActiveServer] = useState<Server | null>(null);
    const [servers, setServers] = useState<Server[]>([
        { id: '1', name: 'Servidor Público 1', players: 12, maxPlayers: 20, ping: 45 },
        { id: '2', name: 'Servidor Público 2', players: 18, maxPlayers: 20, ping: 52 },
        { id: '3', name: 'Solo Amigos', players: 3, maxPlayers: 10, ping: 38 },
    ]);

    const handleJoinServer = (server: Server) => {
        setActiveServer(server);
        setIsPlaying(true);
    };

    const handleCreateServer = () => {
        const newServer: Server = {
            id: Date.now().toString(),
            name: `Servidor de ${user.username}`,
            players: 1,
            maxPlayers: 10,
            ping: 20
        };
        setServers([...servers, newServer]);
        handleJoinServer(newServer);
    };

    const handleQuickPlay = () => {
        // Auto join first server or create random
        handleJoinServer(servers[0]);
    }

    if (isPlaying) {
        return (
            <div className="h-screen w-screen bg-black">
                <StudioPage 
                    onPublish={() => {}} 
                    avatarConfig={avatarConfig} 
                    initialMapData={game.mapData} 
                    isPlayMode={true} 
                    activeServer={activeServer}
                    playerName={user.displayName}
                    onExit={() => setIsPlaying(false)}
                />
            </div>
        );
    }

    return (
        <div className="h-screen w-screen bg-[#232527] text-white overflow-y-auto">
            {/* Banner Blur Background */}
            <div className="absolute top-0 left-0 w-full h-[60vh] overflow-hidden opacity-30 pointer-events-none">
                 <img src={game.thumbnail} className="w-full h-full object-cover blur-xl" />
                 <div className="absolute inset-0 bg-gradient-to-t from-[#232527] via-transparent to-transparent"></div>
            </div>

            <div className="relative max-w-6xl mx-auto pt-20 px-6 z-10 flex flex-col md:flex-row gap-8">
                 {/* Game Thumbnail */}
                 <div className="w-full md:w-[640px] aspect-video bg-black rounded-xl overflow-hidden shadow-2xl border border-gray-700">
                     <img src={game.thumbnail} className="w-full h-full object-cover" />
                 </div>

                 {/* Info & Play */}
                 <div className="flex-1 flex flex-col gap-4">
                     <div>
                         <h1 className="text-4xl font-extrabold mb-2">{game.title}</h1>
                         <div className="flex items-center gap-2 text-gray-400">
                             <span>Por <span className="text-white font-bold hover:underline cursor-pointer">{game.creator}</span></span>
                         </div>
                     </div>

                     <div className="flex items-center gap-6 py-4 border-y border-gray-700">
                         <div className="flex flex-col">
                             <span className="text-lg font-bold text-white">{game.playing.toLocaleString()}</span>
                             <span className="text-xs text-gray-400">Activos</span>
                         </div>
                         <div className="flex flex-col">
                             <span className="text-lg font-bold text-white">{game.likes}</span>
                             <span className="text-xs text-gray-400">Me gusta</span>
                         </div>
                     </div>

                     {/* BIG PLAY BUTTON */}
                     <button 
                        onClick={handleQuickPlay}
                        className="bg-[#00b06f] hover:bg-[#009e63] w-full md:w-48 py-4 rounded-xl flex items-center justify-center gap-3 shadow-lg transform transition-transform active:scale-95"
                     >
                         <div className="bg-white/20 p-1 rounded">
                             <Play fill="white" size={32} />
                         </div>
                         <span className="text-2xl font-bold">Jugar</span>
                     </button>

                     <p className="text-gray-400 text-sm mt-4">
                         Bienvenido a {game.title}. Explora este mundo creado por la comunidad. 
                         {game.mapData ? ' ¡Este es un juego personalizado creado en el Studio!' : ' Este es un juego de ejemplo.'}
                     </p>
                 </div>
            </div>

            {/* SERVER LIST SECTION */}
            <div className="relative max-w-6xl mx-auto mt-12 px-6 pb-20 z-10">
                <div className="flex items-center justify-between mb-6">
                    <h2 className="text-2xl font-bold flex items-center gap-2">
                        <ServerIcon className="text-gray-400" /> Servidores
                    </h2>
                    <button 
                        onClick={handleCreateServer}
                        className="bg-white/10 hover:bg-white/20 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-colors"
                    >
                        <Plus size={16} /> Crear Servidor Privado
                    </button>
                </div>

                <div className="bg-[#2b2d31] rounded-lg border border-gray-700 overflow-hidden">
                    <div className="grid grid-cols-12 gap-4 p-4 bg-[#111213] text-gray-400 text-xs font-bold uppercase tracking-wider">
                        <div className="col-span-5">Nombre del Servidor</div>
                        <div className="col-span-2 text-center">Jugadores</div>
                        <div className="col-span-2 text-center">Ping</div>
